#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
系统托盘：内嵌图标、图标生成、菜单构建与全局 tray_icon 句柄。

tray.py 不直接 import gui，避免循环依赖；菜单回调与窗口回调由 app.py
在创建托盘时通过闭包注入。
"""

import base64
import io

from PIL import Image

import pystray

# 全局托盘句柄，app.py 创建后赋值，gui 退出时读取
tray_icon = None

# 内嵌的 claude.ico 图标（base64编码，无需外部文件）
_ICO_BASE64 = ""


def create_icon_image():
    """从内嵌的 base64 ico 数据生成托盘图标"""
    try:
        ico_data = base64.b64decode(_ICO_BASE64)
        return Image.open(io.BytesIO(ico_data))
    except (OSError, ValueError):
        # 回退：手动绘制图标
        from PIL import ImageDraw
        size = 64
        img = Image.new('RGBA', (size, size), (0, 0, 0, 0))
        draw = ImageDraw.Draw(img)
        # 圆角矩形背景
        draw.rounded_rectangle([2, 2, size-2, size-2], radius=16, fill=(204, 153, 102, 255))
        # C 字母
        draw.arc([10, 10, size-10, size-10], start=45, end=315, fill=(255, 255, 255, 255), width=8)
        return img


def build_menu(port, on_show, on_hide, on_quit, on_toggle_startup):
    """构建托盘菜单。回调由 app.py 注入，避免直接依赖 gui。"""
    from claude_proxy.startup import is_startup_enabled
    startup_text = "开机启动 ✓" if is_startup_enabled() else "开机启动"
    return pystray.Menu(
        pystray.MenuItem(f"端口: {port}", lambda icon, item: None, enabled=False),
        pystray.MenuItem("显示日志窗口", on_show, default=True),
        pystray.MenuItem("隐藏日志窗口", on_hide),
        pystray.MenuItem(startup_text, on_toggle_startup),
        pystray.MenuItem("退出", on_quit),
    )


def get_ico_base64():
    """供 app.py 生成临时 ico 文件时使用。"""
    return _ICO_BASE64
